INSERT INTO `event_registrations` (`id`, `legacy_registration_id`, `event_id`, `user_id`, `event_year`, `registration_status`, `is_confirmed`, `attendance_confirmed`, `is_staff`, `is_admin`, `is_followup`, `welcome_email_sent`, `email_confirmed`, `reasons`, `requires_lodging`, `room_code`, `created_at`, `updated_at`) VALUES
(1, 2015001, 1, 1, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, NULL, 0, NULL, '2026-05-15 18:20:46', '2026-05-15 21:19:11'),
(2, 2015002, 1, 2, '2015', 'A', 0, 0, 1, 0, 0, 0, 0, 'Por que vivo para servir.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(3, 2015003, 1, 3, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Escuche de JUCUM a través de una amiga! Pero realmente quiero ir porque quiero aprender a obedecer a Dios de una manera totalmente diferente a como lo he hecho! Y estoy segura de que Dios tiene mucho que hablarme!', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(4, 2015004, 1, 4, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Unos amigos que son organizadores del evento me invitaron :D, quiero asistir a Reto Urbano para aprender y crecer aún mas en la palabra de Dios y relacionarme con chicos que tengan el mismo deseo que yo.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(5, 2015005, 1, 5, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Me invitaron al evento :) y comentan que es de gran edificación para mi vida, quiero vivir la experiencia y aprender mucho más de Dios.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(6, 2015006, 1, 6, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'ES EL MOMENTO DE DAR UN PASO MAS', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(7, 2015007, 1, 7, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Me encantaría poder asistir a Reto Urbano y conocer un poco más a cerca de mi Señor Jesús.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(8, 2015008, 1, 8, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Para tener mas intimidad con DIOS \r\nConocerlo mas', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(9, 2015009, 1, 9, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'M', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
