(18, 2015018, 1, 18, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'M', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(19, 2015019, 1, 19, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'M', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(20, 2015020, 1, 20, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, NULL, 0, NULL, '2026-05-15 18:20:46', '2026-05-15 21:19:11'),
(21, 2015021, 1, 21, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Me gusta participar', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(22, 2015022, 1, 22, '2015', 'A', 0, 0, 1, 0, 0, 0, 0, 'Para apoyar en lo que necesiten :)', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(23, 2015023, 1, 23, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Porque creo que es un medio que Dios ha puesto para seguir Su llamado. Quiero conocer más gente que tenga el anhelo de servir.  Y el título de \"obediencia radical\" aunque suena difícil es motivador, porque es lo que Dios quiere... y yo quiero seguir ese c', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(24, 2015024, 1, 924, '2015', 'A', 0, 0, 1, 0, 0, 0, 0, 'Quiero ir más profundo en mi relación con Dios, conocerlo aún más y experimentar mejor el darlo a conocer.', 0, NULL, '2026-05-15 18:20:46', '2026-05-17 06:07:38'),
(25, 2015025, 1, 25, '2015', 'A', 0, 0, 1, 0, 0, 0, 0, 'Porque quiero aprender mas, creo que hay mas que ir los domingos a la iglesia y/o participar en actividades \"cristianas\", quiero retarme a vivir de una manera radical y ser cada día mas como Jesús y menos como yo.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(26, 2015026, 1, 26, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Porque quiero conocerle más, tener una experiencia con el y ayudar.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(27, 2015027, 1, 27, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Siempre he querido ser misionera o trabajar en el reino de dios y siento que necesito un encuentro con dios y este reto me ayudara mucho.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(28, 2015028, 1, 28, '2015', 'A', 0, 0, 1, 0, 0, 0, 0, 'Por que necesito alejarme del ambiente en el que siempre convivo, además de que quiero aprender y conocer de Dios', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(29, 2015029, 1, 29, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, NULL, 0, NULL, '2026-05-15 18:20:46', '2026-05-15 21:19:11'),
(30, 2015030, 1, 30, '2015', 'A', 0, 0, 1, 0, 0, 0, 0, 'Love  Jesus', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(31, 2015031, 1, 31, '2015', 'A', 0, 0, 1, 0, 0, 0, 0, 'Porque anteriormente estuve ahí y pude tener un verdadero encuentro con Dios, vivirlo, sentirlo y compartirlo.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(32, 2015032, 1, 32, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Conocer y tener un crecimiento con Dios', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(33, 2015033, 1, 33, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Me gustaría aprender el área de evangelismo, también conocer mas de Dios', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(34, 2015034, 1, 34, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Me gusta el campo misionero', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(35, 2015035, 1, 35, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Para tener un encuentro con Dios', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(36, 2015036, 1, 36, '2015', 'A', 0, 0, 1, 0, 0, 0, 0, 'Fui el año pasado eh experimente cosas maravillosas en la presencia de Dios y lo quiero volver a experimentar', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(37, 2015037, 1, 37, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Porque quiero conocer más a Jesus y acercarme más a él.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(38, 2015038, 1, 38, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Llevo 2 meses de vuelta en la ciudad preparándome para meterme por tiempo completo a las misiones, ha sido una temporada de muchas luchas y trabajo en mi en cuestión a cerrar ciclos, relaciones y dar pasos de obediencia firmes, aun estoy en lucha con much', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(39, 2015039, 1, 39, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'PORQUE QUIERO SEGUIR CONOCIENDO A DIOS Y SEGUIR FORTALECIENDO MI RELACIÓN CON EL MAS ÍNTIMAMENTE  , FORJAR EL CARÁCTER DE DIOS  Y CONOCER MIS DONES QUE DIOS ME A DADO', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(40, 2015040, 1, 40, '2015', 'A', 0, 0, 1, 0, 0, 0, 0, 'Porque quiero', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(41, 2015041, 1, 41, '2015', 'A', 0, 0, 1, 0, 0, 0, 0, 'staff', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(42, 2015042, 1, 42, '2015', 'A', 0, 0, 1, 0, 0, 0, 0, 'nos estara ayudando como chofer', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(43, 2015043, 1, 43, '2015', 'A', 0, 0, 1, 0, 0, 0, 0, 'sera la cocinera estrella', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(44, 2015044, 1, 44, '2015', 'A', 0, 0, 1, 0, 0, 0, 0, 'Porque quiero aprender cada ves mas de Dios y porque me gusta aprender de el creo que estoy en una edad donde servirle a Dios y dar mi vida para servicio de el es esencial asi que estoy ansioso', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(45, 2015045, 1, 1155, '2015', 'A', 0, 0, 1, 0, 0, 0, 0, 'Soy staff', 0, NULL, '2026-05-15 18:20:46', '2026-05-17 06:10:42'),
(46, 2015046, 1, 46, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'Quiero servir a los jóvenes que asistan y las personas que visitaremos. También deseo aprender del equipo Reto Urbano para equipar a los jóvenes de mi iglesia.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(47, 2015047, 1, 47, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'To know God more in His Heart for people, to serve.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(48, 2015048, 1, 48, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'To Know God in a deeper way and to shine his face more brightly in our world.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(49, 2015049, 1, 49, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'I have been a part of the program for the last two years, and i have experience God through many ways. I would like to outreach to others in a different environment.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(50, 2015050, 1, 50, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'I wish to experience God in a different way, and get to know Him a little more. I just want to grow more in Him, so I wish to participate in this Urban Challenge', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(51, 2015051, 1, 51, '2015', 'A', 0, 0, 0, 0, 0, 0, 0, 'To strengthen my relationship with God and to get closer to my church. I would also want to push myself to do more and make the best of my time.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
