(272, 2017127, 3, 275, '2017', 'A', 0, 0, 0, 0, 0, 0, 0, 'Hola! Porque quiero volver a vivir la experiencia,el  RETO pasado me ayudo mucho a acercame mas a Dios y pues me gustaria volver a ir y seguir aprendido mas de Dios y seguir enamorándome de el', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
