(658, 2019104, 5, 661, '2019', 'A', 0, 0, 0, 0, 0, 0, 0, 'MI ANHELO MÁS GRANDE ES CONOCER EN INTIMIDAD MÁS EL CORAZÓN DE MI PADRE, SER ALGUIEN AGRADABLE DELANTE DE SUS OJOS Y PODER GLORIFICARLO EN LO QUE PIENSO, LO QUE DIGO Y LO QUE HAGO. \nHE PROBADO LA GENUINA GRACIA DE PAPÁ Y HE QUEDADO MARCADO POR ELLA.', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(659, 2019105, 5, 662, '2019', 'A', 0, 0, 0, 0, 0, 0, 0, 'PARA MÍ ES DE GRAN BENDICIÓN EL IR A JUCUM PUES SE QUE ME AYUDARÁ A MI FORMACIÓN TANTO ESPIRITUAL COMO PERSONAL, PUES PODRÉ AÚN DESARROLLAR LOS TALENTOS QUE DIOS ME A DADO Y USARLOS PRINCIPALMENTE PARA SU SERVICIO; TAMBIÉN PODER CRECER EN ÁREAS DE MI VIDA', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(660, 2019106, 5, 663, '2019', 'A', 0, 0, 0, 0, 0, 0, 0, 'BUENO LA RAZON POR LA CUAL DESEO PARTICIPAR EN RETO URBANO ES PARA LOGRAR ESTRECHAR Y LLEVAR AUN MAS LEJOS MI RELACION CON DIOS Y LOGRAR SER CAPAZ DE COMPARTIR SU AMOR A DIFERENTES PERSONAS SER UNA VIVA MUESTRA DEL AMOR DE DIOS HACIA LAS PERSONAS', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(661, 2019107, 5, 664, '2019', 'A', 0, 0, 0, 0, 0, 0, 0, 'PORQUE YA EH IDO AÑOS ANTERIORES Y AMO REENCONTRARME CON DIOS MEDIANTE UN RETO. Y SIENTO QUE NECESITO VOLVER A EL', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(662, 2019108, 5, 665, '2019', 'A', 0, 0, 0, 0, 0, 0, 0, 'PARA SERVIR Y PONER EN PRÁCTICA LO QUE APRENDÍ EN SEGUIMIENTO', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
(663, 2019109, 5, 666, '2019', 'A', 0, 0, 0, 0, 0, 0, 0, 'Y ME GUSTARÍA IR PORQUE QUISIERA SERVIR A DIOS DE UNA MANERA DISTINTA A LA QUE YO LE SIRVO Y TAMBIÉN PARA CONOCER A PERSONAS CON EL MISMO CORAZÓN Y LAS MISMAS INTENCIONES DE SERVIR A DIOS', 0, NULL, '2026-05-15 18:20:46', '2026-05-15 22:04:56'),
